
    (function(){
      // Sample videos (local files generated by generate_videos.sh)
      const videos = [
        {id:1,title:'Big Buck Bunny',src:'videos/video1.mp4',poster:''},
        {id:2,title:'Elephants Dream',src:'videos/video2.mp4',poster:''},
        {id:3,title:'For Bigger Blazes',src:'videos/video3.mp4',poster:''},
        {id:4,title:'Sintel Trailer',src:'videos/video4.mp4',poster:''},
        {id:5,title:'Tears of Steel',src:'videos/video5.mp4',poster:''},
        {id:6,title:'For Bigger Escape',src:'videos/video6.mp4',poster:''},
        {id:7,title:'Subaru Outback',src:'videos/video7.mp4',poster:''},
        {id:8,title:'Volkswagen GTI Review',src:'videos/video8.mp4',poster:''}
      ]

      const STORAGE_KEY = 'yutoob_stats'
      let stats = {}
      try{ stats = JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}') }catch(e){ stats = {} }

      function saveStats(){ localStorage.setItem(STORAGE_KEY, JSON.stringify(stats)) }

      function recommend(list){
        return list.slice().map(v=>{
          const s = stats[v.id] || {watchTime:0,liked:false}
          const score = (s.watchTime||0) + (s.liked?600:0)
          return Object.assign({},v,{score})
        }).sort((a,b)=>b.score-a.score)
      }

      // DOM helpers
      const $ = sel => document.querySelector(sel)
      const $$ = sel => Array.from(document.querySelectorAll(sel))

      let searchTerm = ''
      let currentPage = 'home'
      let currentGame = 'beat-tiles'
      let beatAnimationId = null
      let racerAnimationId = null
      let obbyAnimationId = null
      let tycoonIntervalId = null
      let lastRenderPage = null
      let beatAudio = null

      const beatSongs = [
        { id:'pulsar', title:'Pulsar Beat', artist:'Future City', src:'https://assets.mixkit.co/music/preview/mixkit-electro-future-ambient-541.mp3' },
        { id:'neon-drive', title:'Neon Drive', artist:'Skyline Pulse', src:'https://assets.mixkit.co/music/preview/mixkit-futuristic-electronic-1160.mp3' },
        { id:'hypercore', title:'Hypercore', artist:'Pulse Grid', src:'https://assets.mixkit.co/music/preview/mixkit-futuristic-technology-563.mp3' }
      ]

      const beatDifficulties = {
        easy: { label:'Easy', speed: 170, span: 1100, tileDensity: 1 },
        normal: { label:'Normal', speed: 220, span: 900, tileDensity: 1.25 },
        hard: { label:'Hard', speed: 280, span: 720, tileDensity: 1.5 }
      }

      const gameState = {
        beat: {
          score: 0,
          combo: 0,
          accuracy: 'Ready',
          tiles: [],
          lastSpawn: 0,
          speed: 220,
          spawnInterval: 900,
          running: false,
          selectedSong: 'pulsar',
          difficulty: 'normal'
        },
        tycoon: {
          cash: 90,
          income: 1.4,
          level: 1,
          multiplier: 1,
          upgrades: 0,
          lastTick: Date.now()
        },
        obby: {
          position: 1,
          score: 0,
          alive: true,
          obstacles: [],
          lastTime: 0,
          spawnCounter: 0,
          speed: 240,
          boost: 0,
          cooldown: 0
        },
        spaceRacer: {
          position: 1,
          score: 0,
          speed: 220,
          obstacles: [],
          lastTime: 0,
          spawnTimer: 0,
          boost: 0,
          cooldown: 0,
          distance: 0
        },
        puzzleGrid: {
          tiles: [],
          firstPick: null,
          secondPick: null,
          moves: 0,
          matches: 0,
          locked: false
        }
      }

      const webResults = [
        {title:'Yutoob Search Engine', url:'#', description:'A warm search experience that integrates Yutoob video discovery.'},
        {title:'Yutoob Videos', url:'#', description:'Find local Yutoob videos, watch them instantly, and get personalized recommendations.'},
        {title:'Yutoob Browser', url:'#', description:'A search browser home page with an integrated video playground.'}
      ]

      function executeSearch(){
        currentPage = 'results'
        render()
      }

      function render(){
        const root = document.getElementById('app')
        root.innerHTML = ''

        const topbar = document.createElement('header')
        topbar.className='topbar'
        topbar.innerHTML = `<a class="skip" href="#main-content">Skip to content</a><div class="logo">Yutoob Search</div><div class="search-row"><input class="search" placeholder="Search the web" aria-label="Search the web"></div><button class="btn-primary" id="search-button">Search</button>`

        const layout = document.createElement('div'); layout.className='layout'
        const sidebar = document.createElement('aside'); sidebar.className='sidebar'; sidebar.setAttribute('role','navigation')
        sidebar.innerHTML = `
          <button class="side-item ${currentPage === 'home' ? 'active' : ''}" data-page="home">Home</button>
          <button class="side-item ${currentPage === 'results' ? 'active' : ''}" data-page="results">Search</button>
          <button class="side-item ${currentPage === 'games' ? 'active' : ''}" data-page="games">Games</button>
          <button class="side-item ${currentPage === 'about' ? 'active' : ''}" data-page="about">About</button>
        `
        const main = document.createElement('main'); main.className='main'; main.id='main-content'; main.setAttribute('role','main');

        const hero = document.createElement('section'); hero.className='hero'
        if(currentPage === 'home'){
          hero.innerHTML = `<div><h1>Search the web with Yutoob</h1><p>Video search, local playback, and a friendly browsing experience all in one place.</p></div><div class="hero-search"><input class="hero-input" type="search" placeholder="Search anything" value="${searchTerm}" aria-label="Search" /><button class="btn-primary" id="hero-search">Search</button></div>`
          main.appendChild(hero)
          const prompt = document.createElement('div')
          prompt.className = 'hero-sub'
          prompt.innerHTML = '<p>Use the search bar above to find Yutoob results and Yutoob videos.</p>'
          main.appendChild(prompt)
          const adCard = document.createElement('section')
          adCard.className = 'game-ad-card'
          adCard.innerHTML = `<div><span class="ad-chip">Game Hub</span><h2>Play the new Yutoob Game Hub</h2><p>Try Beat Tiles, Cyber Tycoon, Space Racer, Neon Obby, or Puzzle Grid right now. Press the button to jump straight into the arcade.</p></div><div class="game-ad-image"></div><button class="btn-primary" id="game-ad-open">Open Games</button>`
          main.appendChild(adCard)
        } else if(currentPage === 'games'){
          hero.innerHTML = `<div><h1>Future arcade in a click</h1><p>Choose a futuristic minigame and play Beat Tiles, Space Racer, Cyber Tycoon, Neon Obby, or Puzzle Grid.</p></div>`
          main.appendChild(hero)
        } else if(currentPage === 'about'){
          hero.innerHTML = `<div><h1>About Yutoob</h1><p>The future of video discovery, local playback and new game modes in one glowing experience.</p></div>`
          main.appendChild(hero)
          const prompt = document.createElement('div')
          prompt.className = 'hero-sub'
          prompt.innerHTML = '<p>Try the new Games tab for rhythm, tycoon, and obstacle course action.</p>'
          main.appendChild(prompt)
        } else {
          hero.innerHTML = `<div><h1>Search results for "${searchTerm}"</h1><p>Showing web results and Yutoob video recommendations.</p></div>`
          main.appendChild(hero)
        }

        if(currentPage === 'results'){
          const resultsSection = document.createElement('section'); resultsSection.className = 'results-section'
          const webList = document.createElement('div'); webList.className='web-results'
          webResults.forEach(item => {
            const card = document.createElement('div'); card.className='web-card'
            card.innerHTML = `<a class="web-title" href="${item.url}">${item.title}</a><p class="web-description">${item.description}</p>`
            webList.appendChild(card)
          })
          resultsSection.appendChild(webList)

          const videoHeading = document.createElement('div'); videoHeading.className='video-heading'; videoHeading.innerHTML = '<h2>Yutoob video results</h2>'
          main.appendChild(resultsSection)
          main.appendChild(videoHeading)

          const grid = document.createElement('div'); grid.className='grid'
          const list = recommend(videos).filter(v => v.title.toLowerCase().includes(searchTerm.toLowerCase()))
          list.forEach(v=>{
            const s = stats[v.id] || {watchTime:0,liked:false}
            const watched = Math.floor((s.watchTime||0)/60)
            const badgeText = s.liked ? '♥' : (s.watchTime > 120 ? '🔥' : (watched ? watched + 'm' : 'New'))
            const card = document.createElement('div'); card.className='video-card'
            card.tabIndex = 0
            card.setAttribute('role','button')
            card.setAttribute('aria-label', `Open video ${v.title}`)
            const poster = v.poster || 'https://via.placeholder.com/320x180?text=Video'
            card.innerHTML = `<div class="thumb"><img src="${poster}" alt="${v.title}"><div class="score-badge">${badgeText}</div><button class="like-btn" aria-label="${s.liked ? 'Unlike' : 'Like'}">${s.liked ? '♥' : '♡'}</button></div><div class="meta"><div class="title">${v.title}</div><div class="channel">Yutoob Channel • ${watched} min</div></div>`
            card.addEventListener('click',()=>openPlayer(v))
            card.addEventListener('keydown',e=>{ if(e.key === 'Enter' || e.key === ' ') { e.preventDefault(); openPlayer(v) } })
            const likeBtn = card.querySelector('.like-btn')
            likeBtn.addEventListener('click',e=>{ e.stopPropagation(); toggleLike(v.id); likeBtn.setAttribute('aria-label', (stats[v.id] && stats[v.id].liked) ? 'Unlike' : 'Like') })
            grid.appendChild(card)
          })
          main.appendChild(grid)
        }

        if(currentPage === 'games'){
          main.appendChild(renderGames())
        }

        layout.appendChild(sidebar)
        layout.appendChild(main)
        root.appendChild(topbar)
        root.appendChild(layout)

        const searchEl = topbar.querySelector('.search')
        const heroInput = main.querySelector('.hero-input')
        const searchButton = topbar.querySelector('#search-button')
        const heroButton = main.querySelector('#hero-search')

        function attachSearch(el){
          if(!el) return
          el.value = searchTerm
          el.addEventListener('input', e => { searchTerm = e.target.value })
          el.addEventListener('keydown', e => { if(e.key === 'Enter'){ executeSearch() } })
        }
        attachSearch(searchEl)
        attachSearch(heroInput)

        if(searchButton) searchButton.addEventListener('click', executeSearch)
        if(heroButton) heroButton.addEventListener('click', executeSearch)
        const gameAdButton = document.getElementById('game-ad-open')
        if(gameAdButton){
          gameAdButton.addEventListener('click', () => {
            currentPage = 'games'
            currentGame = 'beat-tiles'
            stopAllGameLoops()
            render()
          })
        }

        sidebar.querySelectorAll('[data-page]').forEach(btn => {
          btn.addEventListener('click', () => {
            const page = btn.getAttribute('data-page')
            if(page === 'games' && currentPage !== 'games'){
              currentPage = 'games'
              currentGame = 'beat-tiles'
            } else if(page !== currentPage){
              currentPage = page
            }
            stopAllGameLoops()
            render()
          })
        })

        renderDebug()
      }

      // Player
      let current = null
      let playStart = null

      function openPlayer(v){
        current = v
        const modal = document.createElement('div'); modal.className='modal'
        modal.tabIndex = -1
        modal.setAttribute('role','dialog')
        modal.setAttribute('aria-modal','true')
        const player = document.createElement('div'); player.className='player'
        player.innerHTML = `<video controls autoplay src="${v.src}" poster="${v.poster||''}"></video><div class="player-title">${v.title}</div><div style="padding:0 12px 12px"><button id="player-like" class="btn" aria-label="${(stats[v.id]&&stats[v.id].liked)?'Unlike':'Like'}">${(stats[v.id]&&stats[v.id].liked)?'Unlike':'Like'}</button></div>`
        modal.appendChild(player)
        modal.addEventListener('click',closePlayer)
        player.addEventListener('click',e=>e.stopPropagation())
        document.body.appendChild(modal)
        modal.focus()

        const videoEl = player.querySelector('video')
        videoEl.setAttribute('aria-label', v.title)
        videoEl.addEventListener('play',()=>{
          playStart = Date.now()
        })
        function addDelta(){
          if(!playStart) return
          const delta = Math.floor((Date.now()-playStart)/1000)
          playStart = null
          stats[v.id] = stats[v.id] || {watchTime:0,liked:false}
          stats[v.id].watchTime = (stats[v.id].watchTime||0) + delta
          saveStats()
          render()
        }
        videoEl.addEventListener('pause', addDelta)
        videoEl.addEventListener('ended', addDelta)

        const likeBtn = player.querySelector('#player-like')
        likeBtn.addEventListener('click',()=>{ toggleLike(v.id); likeBtn.textContent = (stats[v.id]&&stats[v.id].liked)?'Unlike':'Like' })

        modal.addEventListener('keydown', e => { if(e.key === 'Escape') closePlayer() })
      }

      function closePlayer(){
        // if video playing, add delta
        if(playStart && current){
          const delta = Math.floor((Date.now()-playStart)/1000)
          stats[current.id] = stats[current.id] || {watchTime:0,liked:false}
          stats[current.id].watchTime = (stats[current.id].watchTime||0) + delta
          playStart = null
        }
        const modal = document.querySelector('.modal')
        if(modal) modal.remove()
        current = null
        saveStats()
        render()
      }

      function toggleLike(id){
        stats[id] = stats[id] || {watchTime:0,liked:false}
        stats[id].liked = !stats[id].liked
        saveStats()
        render()
      }

      function stopAllGameLoops(){
        if(beatAnimationId){ cancelAnimationFrame(beatAnimationId); beatAnimationId = null }
        if(racerAnimationId){ cancelAnimationFrame(racerAnimationId); racerAnimationId = null }
        if(obbyAnimationId){ cancelAnimationFrame(obbyAnimationId); obbyAnimationId = null }
        if(tycoonIntervalId){ clearInterval(tycoonIntervalId); tycoonIntervalId = null }
        document.removeEventListener('keydown', handleBeatKeydown)
        document.removeEventListener('keydown', handleRacerKeydown)
        document.removeEventListener('keydown', handleObbyKeydown)
        if(beatAudio){ beatAudio.pause(); beatAudio = null }
      }

      function renderGames(){
        const gamesRoot = document.createElement('div')
        const title = document.createElement('section'); title.className='hero'
        title.innerHTML = `<div><h1>Play in neon mode</h1><p>Jump into a futuristic game hub with rhythm, tycoon, and obby challenges.</p></div>`
        gamesRoot.appendChild(title)

        const modeRow = document.createElement('div'); modeRow.className='game-mode-row'
        const modes = [
          { id:'beat-tiles', title:'Beat Tiles', description:'Tap the neon track when falling tiles hit the center zone for perfect+ timing.', icon:'🎵' },
          { id:'tycoon', title:'Cyber Tycoon', description:'Build a glowing business, buy upgrades, and watch the credits flow.', icon:'💎' },
          { id:'space-racer', title:'Space Racer', description:'Tune the hyperdrive gauge and align energy pulses in a futuristic charge run.', icon:'🚀' },
          { id:'obby', title:'Neon Obby', description:'Build a glowing route through a neon circuit with timing and logic.', icon:'🏃' },
          { id:'puzzle-grid', title:'Puzzle Grid', description:'Match the glowing tiles in a futuristic board puzzle mission.', icon:'🧩' }
        ]
        modes.forEach(mode => {
          const card = document.createElement('button')
          card.type = 'button'
          card.className = 'game-card-mini' + (currentGame === mode.id ? ' active' : '')
          card.innerHTML = `<div class="card-icon">${mode.icon}</div><h3>${mode.title}</h3><p>${mode.description}</p>`
          card.addEventListener('click', () => {
            currentGame = mode.id
            stopAllGameLoops()
            render()
          })
          modeRow.appendChild(card)
        })
        gamesRoot.appendChild(modeRow)

        const panel = document.createElement('div'); panel.className = 'game-panel'
        if(currentGame === 'beat-tiles'){
          renderBeatTiles(panel)
        } else if(currentGame === 'tycoon'){
          renderTycoonPanel(panel)
        } else if(currentGame === 'space-racer'){
          renderRacerPanel(panel)
        } else if(currentGame === 'obby'){
          renderObbyPanel(panel)
        } else if(currentGame === 'puzzle-grid'){
          renderPuzzlePanel(panel)
        }
        gamesRoot.appendChild(panel)
        return gamesRoot
      }

      function renderBeatTiles(container){
        const state = gameState.beat
        const song = beatSongs.find(s => s.id === state.selectedSong) || beatSongs[0]
        const difficulty = beatDifficulties[state.difficulty]

        const header = document.createElement('div'); header.className = 'game-info'
        header.innerHTML = `<div class="game-score-card"><strong>Beat Tiles</strong><span>${state.score} pts</span><p>Now playing: ${song.title} — ${song.artist}</p></div>`
        container.appendChild(header)

        const controls = document.createElement('div'); controls.className='game-actions'
        const songLabel = document.createElement('div'); songLabel.style.flex='1'
        songLabel.innerHTML = `<strong style="display:block;margin-bottom:6px;color:#fff">Song</strong>`
        const songSelect = document.createElement('select')
        songSelect.style.width='100%'
        beatSongs.forEach(s => {
          const option = document.createElement('option')
          option.value = s.id
          option.textContent = `${s.title} — ${s.artist}`
          if(s.id === state.selectedSong) option.selected = true
          songSelect.appendChild(option)
        })
        songSelect.addEventListener('change', () => {
          state.selectedSong = songSelect.value
          updateBeatAudio()
          render()
        })
        songLabel.appendChild(songSelect)
        controls.appendChild(songLabel)

        const difficultySelector = document.createElement('div'); difficultySelector.style.display='flex'; difficultySelector.style.gap='10px'; difficultySelector.style.flex='1';
        Object.keys(beatDifficulties).forEach(key => {
          const diff = beatDifficulties[key]
          const btn = document.createElement('button'); btn.className='btn' + (state.difficulty === key ? ' active' : ''); btn.textContent = diff.label
          btn.addEventListener('click', () => {
            state.difficulty = key
            state.speed = diff.speed
            state.spawnInterval = diff.span
            render()
          })
          difficultySelector.appendChild(btn)
        })
        controls.appendChild(difficultySelector)
        container.appendChild(controls)

        const board = document.createElement('div'); board.className = 'game-board'
        const canvas = document.createElement('canvas'); canvas.id = 'beat-canvas'; canvas.width = 760; canvas.height = 520
        board.appendChild(canvas)
        container.appendChild(board)

        if(beatAudio){ beatAudio.pause(); beatAudio = null }
        const audioPlayer = document.createElement('audio'); audioPlayer.id='beat-audio'; audioPlayer.style.width='100%'; audioPlayer.controls = true; audioPlayer.autoplay = true; audioPlayer.loop = true; audioPlayer.src = song.src
        container.appendChild(audioPlayer)
        beatAudio = audioPlayer

        const actions = document.createElement('div'); actions.className = 'game-actions'
        const hotkeys = ['D','F','J','K']
        hotkeys.forEach((key, idx) => {
          const btn = document.createElement('button'); btn.className = 'btn'; btn.textContent = `Tap ${key}`
          btn.addEventListener('click', () => hitBeatTile(idx))
          actions.appendChild(btn)
        })
        container.appendChild(actions)

        const tips = document.createElement('div'); tips.className = 'game-tips'
        tips.innerHTML = `<p><strong class="futuristic-text">Accuracy:</strong> ${state.accuracy} · <strong class="futuristic-text">Combo:</strong> ${state.combo} · <strong class="futuristic-text">Mode:</strong> ${difficulty.label}</p><p>Use D / F / J / K or tap the buttons. Harder songs and harder modes push the timing window tighter.</p>`
        container.appendChild(tips)

        if(!beatAnimationId){
          state.running = true
          state.lastTime = performance.now()
          state.lastSpawn = performance.now()
          state.speed = difficulty.speed
          state.spawnInterval = difficulty.span
          document.addEventListener('keydown', handleBeatKeydown)
          beatAnimationId = requestAnimationFrame(beatLoop)
        }
      }

      function updateBeatAudio(){
        const song = beatSongs.find(s => s.id === gameState.beat.selectedSong) || beatSongs[0]
        const audio = document.getElementById('beat-audio')
        if(audio){
          audio.src = song.src
          audio.play().catch(() => {})
        }
      }

      function handleBeatKeydown(event){
        const mapping = { d:0, f:1, j:2, k:3 }
        const key = event.key.toLowerCase()
        if(mapping[key] !== undefined){
          hitBeatTile(mapping[key])
        }
      }

      function hitBeatTile(lane){
        const state = gameState.beat
        const targetY = 460
        const candidates = state.tiles.filter(tile => tile.lane === lane)
        if(!candidates.length){ state.accuracy = 'Miss'; state.combo = 0; return }
        let best = null
        candidates.forEach(tile => {
          const diff = Math.abs((tile.y + 36) - targetY)
          if(!best || diff < best.diff){ best = { tile, diff } }
        })
        if(!best || best.diff > 90){ state.accuracy = 'Miss'; state.combo = 0; return }
        const dist = best.diff
        let score = 0
        let text = 'Good'
        if(dist < 12){ text = 'Perfect+'; score = 360 }
        else if(dist < 28){ text = 'Perfect'; score = 260 }
        else if(dist < 52){ text = 'Great'; score = 160 }
        else { text = 'Good'; score = 90 }
        state.score += score + state.combo * 4
        state.combo += 1
        state.accuracy = text
        state.tiles = state.tiles.filter(tile => tile !== best.tile)
      }

      function beatLoop(timestamp){
        const state = gameState.beat
        const difficulty = beatDifficulties[state.difficulty]
        const dt = (timestamp - state.lastTime) / 1000
        state.lastTime = timestamp
        if(timestamp - state.lastSpawn > state.spawnInterval){
          const count = Math.max(1, Math.round(difficulty.tileDensity))
          for(let i=0;i<count;i++){
            state.tiles.push({ lane: Math.floor(Math.random() * 4), y: -68 - i * 42, id: `tile-${Date.now()}-${Math.random()}` })
          }
          state.lastSpawn = timestamp
        }
        const speed = state.speed + state.score * 0.02
        state.tiles.forEach(tile => tile.y += speed * dt)
        state.tiles = state.tiles.filter(tile => {
          if(tile.y > 540){ state.accuracy = 'Miss'; state.combo = 0; return false }
          return true
        })
        drawBeatGame()
        if(currentPage === 'games' && currentGame === 'beat-tiles'){
          beatAnimationId = requestAnimationFrame(beatLoop)
        } else {
          beatAnimationId = null
        }
      }

      function drawBeatGame(){
        const canvas = document.getElementById('beat-canvas')
        if(!canvas) return
        const ctx = canvas.getContext('2d')
        ctx.clearRect(0,0,canvas.width,canvas.height)
        const grad = ctx.createLinearGradient(0,0,0,canvas.height)
        grad.addColorStop(0,'#1b0904'); grad.addColorStop(1,'#0c0502')
        ctx.fillStyle = grad
        ctx.fillRect(0,0,canvas.width,canvas.height)
        const laneWidth = 140
        const gap = 20
        const startX = 70
        for(let i=0;i<4;i++){
          const x = startX + i * (laneWidth + gap)
          ctx.fillStyle = 'rgba(255,142,64,0.12)'
          ctx.fillRect(x, 0, laneWidth, canvas.height)
          ctx.strokeStyle = 'rgba(255,142,64,0.18)'
          ctx.lineWidth = 2
          ctx.strokeRect(x, 0, laneWidth, canvas.height)
          ctx.fillStyle = 'rgba(255,142,64,0.06)'
          ctx.fillRect(x, 420, laneWidth, 110)
        }
        const targetY = 460
        ctx.strokeStyle = 'rgba(255,142,64,0.85)'
        ctx.lineWidth = 4
        ctx.beginPath(); ctx.moveTo(startX, targetY); ctx.lineTo(startX + 4*(laneWidth+gap) - gap, targetY); ctx.stroke()
        ctx.fillStyle = 'rgba(255,142,64,0.16)'
        ctx.fillRect(startX, targetY - 34, 4*(laneWidth+gap) - gap, 68)
        gameState.beat.tiles.forEach(tile => {
          const x = startX + tile.lane * (laneWidth + gap) + 10
          ctx.fillStyle = 'rgba(255,142,64,0.95)'
          ctx.shadowColor = 'rgba(255,142,64,0.45)'
          ctx.shadowBlur = 22
          ctx.fillRect(x, tile.y, laneWidth - 20, 48)
          ctx.shadowBlur = 0
        })
        ctx.fillStyle = '#fff1dc'
        ctx.font = '700 22px Inter'
        ctx.fillText(`Score: ${gameState.beat.score}`, 28, 42)
        ctx.fillText(`Combo: ${gameState.beat.combo}`, 28, 74)
        ctx.fillStyle = '#f4c99a'
        ctx.font = '600 18px Inter'
        ctx.fillText(`Hit: ${gameState.beat.accuracy}`, 28, 104)
      }

      function drawTycoonScene(){
        const canvas = document.getElementById('tycoon-canvas')
        if(!canvas) return
        const ctx = canvas.getContext('2d')
        const width = canvas.width
        const height = canvas.height
        ctx.clearRect(0,0,width,height)

        const bg = ctx.createLinearGradient(0,0,0,height)
        bg.addColorStop(0,'rgba(20,10,4,0.95)')
        bg.addColorStop(1,'rgba(10,4,2,0.9)')
        ctx.fillStyle = bg
        ctx.fillRect(0,0,width,height)

        const horizon = 120
        ctx.strokeStyle = 'rgba(255,142,64,0.18)'
        ctx.lineWidth = 2
        ctx.beginPath()
        ctx.moveTo(90,horizon)
        ctx.lineTo(width-90,horizon)
        ctx.stroke()

        ctx.fillStyle = 'rgba(255,142,64,0.06)'
        ctx.fillRect(80, horizon, width-160, height-horizon)

        const cube = (x,y,s,angle) => {
          ctx.save()
          ctx.translate(x,y)
          ctx.rotate(angle)
          ctx.fillStyle = 'rgba(255,178,120,0.95)'
          ctx.fillRect(-s/2, -s/2, s, s)
          ctx.fillStyle = 'rgba(255,142,64,0.75)'
          ctx.fillRect(-s/2, -s/2, s, s*0.4)
          ctx.restore()
        }

        cube(240,180,92,-0.12)
        cube(430,200,76,0.16)
        cube(550,150,110,-0.06)

        const glow = ctx.createRadialGradient(420, 140, 10, 420, 140, 110)
        glow.addColorStop(0,'rgba(255,196,141,0.55)')
        glow.addColorStop(1,'rgba(255,142,64,0)')
        ctx.fillStyle = glow
        ctx.fillRect(220, 40, 320, 220)

        ctx.fillStyle = '#fff1dc'
        ctx.font = '700 20px Inter'
        ctx.fillText('3D Arcade Vault', 32, 34)
        ctx.font = '500 14px Inter'
        ctx.fillStyle = '#f4c99a'
        ctx.fillText('Build your cyber business inside the hub.', 32, 58)
      }

      function renderTycoonPanel(container){
        const state = gameState.tycoon
        const header = document.createElement('div'); header.className = 'game-info'
        header.innerHTML = `<div class="game-score-card"><strong>Cyber Tycoon</strong><span>$${Math.floor(state.cash)}</span><p>Grow income, buy upgrades, and experience futuristic passive gains.</p></div>`
        container.appendChild(header)

        const scene = document.createElement('div'); scene.className = 'tycoon-scene'
        const canvas = document.createElement('canvas'); canvas.id = 'tycoon-canvas'; canvas.width = 760; canvas.height = 240
        scene.appendChild(canvas)
        container.appendChild(scene)
        drawTycoonScene()

        const stats = document.createElement('div'); stats.className = 'game-score-card'
        stats.innerHTML = `<strong>Income / second</strong><span>$${state.income.toFixed(1)}</span><p>Level ${state.level} · Multiplier x${state.multiplier.toFixed(1)}</p>`
        container.appendChild(stats)

        const actions = document.createElement('div'); actions.className = 'game-actions'
        const buttons = [
          { label: 'Collect Boost', action: () => { state.cash += 18; render() } },
          { label: `Buy Upgrade ($${40 + state.upgrades * 30})`, action: () => {
            const cost = 40 + state.upgrades * 30
            if(state.cash >= cost){ state.cash -= cost; state.income += 1.4 * state.multiplier; state.upgrades += 1; state.level += 1; render() }
          } },
          { label: `Launch Neon Vault ($${110 + state.upgrades * 25})`, action: () => {
            const cost = 110 + state.upgrades * 25
            if(state.cash >= cost){ state.cash -= cost; state.multiplier += 0.3; state.income += 2; render() }
          } },
          { label: `Sell Cyber Ads ($${20 + state.level * 10})`, action: () => {
            const earn = 20 + state.level * 10
            state.cash += earn
            state.income += 0.15
            render()
          } }
        ]
        buttons.forEach(btn => {
          const node = document.createElement('button'); node.className='btn'; node.textContent = btn.label
          node.addEventListener('click', btn.action)
          actions.appendChild(node)
        })
        container.appendChild(actions)
        const tips = document.createElement('div'); tips.className='game-tips'
        tips.innerHTML = '<p>Every second your business earns credits automatically. Use boosts, vault launches, and ad sales to stay ahead of the curve.</p>'
        container.appendChild(tips)
        if(!tycoonIntervalId){ startTycoonMode() }
      }

      function startTycoonMode(){
        if(tycoonIntervalId) return
        tycoonIntervalId = setInterval(() => {
          const state = gameState.tycoon
          state.cash += state.income
          if(currentPage === 'games' && currentGame === 'tycoon'){
            render()
          }
        }, 1000)
      }

      function renderObbyPanel(container){
        const state = gameState.obby
        if(!state.pattern.length){ initObbyPattern() }
        const header = document.createElement('div'); header.className = 'game-info'
        header.innerHTML = `<div class="game-score-card"><strong>Neon Obby</strong><span>${state.score} pts</span><p>Build a glowing route through a neon circuit with timing and logic.</p></div>`
        container.appendChild(header)

        const board = document.createElement('div'); board.className='game-board obby-perspective'
        const canvas = document.createElement('canvas'); canvas.id='obby-canvas'; canvas.width = 760; canvas.height = 420
        board.appendChild(canvas)
        container.appendChild(board)

        const actions = document.createElement('div'); actions.className='game-actions'
        const leftBtn = document.createElement('button'); leftBtn.className='btn'; leftBtn.textContent='Left'; leftBtn.addEventListener('click', () => moveObby(-1))
        const rightBtn = document.createElement('button'); rightBtn.className='btn'; rightBtn.textContent='Right'; rightBtn.addEventListener('click', () => moveObby(1))
        const placeBtn = document.createElement('button'); placeBtn.className='btn'; placeBtn.textContent='Place'; placeBtn.addEventListener('click', placeObbySegment)
        const restartBtn = document.createElement('button'); restartBtn.className='btn'; restartBtn.textContent='Restart'; restartBtn.addEventListener('click', resetObby)
        actions.append(leftBtn, rightBtn, placeBtn, restartBtn)
        container.appendChild(actions)

        const tips = document.createElement('div'); tips.className='game-tips'
        tips.innerHTML = `<p>Select the right lane and place energy nodes to extend the path. Complete the pattern to finish the circuit.</p><p>Wrong placements reset the route, so keep timing steady.</p>`
        container.appendChild(tips)

        if(!obbyAnimationId){
          state.lastTime = performance.now()
          state.alive = true
          document.addEventListener('keydown', handleObbyKeydown)
          obbyAnimationId = requestAnimationFrame(obbyLoop)
        }
      }

      function initObbyPattern(){
        const state = gameState.obby
        state.pattern = Array.from({length: 7}, () => Math.floor(Math.random() * 3))
        state.path = []
        state.goalIndex = 0
        state.score = 0
        state.alive = true
        state.cooldown = 0
        state.phase = 0
      }

      function initPuzzleGrid(){
        const state = gameState.puzzleGrid
        const values = ['★','▲','●','■','◆','☀','⟁','✦']
        state.tiles = [...values, ...values].sort(() => Math.random() - 0.5).map((value, index) => ({
          id: `tile-${index}`,
          value,
          revealed: false,
          matched: false
        }))
        state.firstPick = null
        state.secondPick = null
        state.moves = 0
        state.matches = 0
        state.locked = false
      }

      function renderPuzzlePanel(container){
        const state = gameState.puzzleGrid
        if(!state.tiles.length){
          initPuzzleGrid()
        }

        const header = document.createElement('div'); header.className = 'game-info'
        header.innerHTML = `<div class="game-score-card"><strong>Puzzle Grid</strong><span>${state.matches * 100}</span><p>Find matching neon tiles and clear the board.</p></div>`
        container.appendChild(header)

        const banner = document.createElement('div'); banner.className = 'game-banner'
        banner.style.backgroundImage = "url('https://images.unsplash.com/photo-1516574187841-cb9cc2ca948b?auto=format&fit=crop&w=900&q=80')"
        banner.innerHTML = `<h3>Match glowing tiles</h3><p>Flip tiles and pair the icons before the board fills.</p>`
        container.appendChild(banner)

        const grid = document.createElement('div'); grid.className = 'puzzle-grid'
        state.tiles.forEach((tile, index) => {
          const btn = document.createElement('button'); btn.type = 'button'
          btn.className = 'puzzle-tile' + (tile.revealed || tile.matched ? ' revealed' : '') + (tile.matched ? ' matched' : '')
          btn.textContent = tile.revealed || tile.matched ? tile.value : ''
          btn.addEventListener('click', () => handlePuzzlePick(index))
          grid.appendChild(btn)
        })
        container.appendChild(grid)

        const stats = document.createElement('div'); stats.className = 'game-stats'
        stats.innerHTML = `<div class="game-score-card"><strong>Moves</strong><span>${state.moves}</span></div><div class="game-score-card"><strong>Matches</strong><span>${state.matches}/8</span></div><div class="game-score-card"><strong>Status</strong><span>${state.matches === 8 ? 'Victory' : state.locked ? 'Waiting' : 'Ready'}</span></div>`
        container.appendChild(stats)

        const actions = document.createElement('div'); actions.className='game-actions'
        const resetBtn = document.createElement('button'); resetBtn.className='btn'; resetBtn.textContent='Shuffle'; resetBtn.addEventListener('click', () => { initPuzzleGrid(); render() })
        actions.appendChild(resetBtn)
        container.appendChild(actions)
      }

      function handlePuzzlePick(index){
        const state = gameState.puzzleGrid
        if(state.locked) return
        const tile = state.tiles[index]
        if(tile.revealed || tile.matched) return
        tile.revealed = true
        if(!state.firstPick){
          state.firstPick = tile
        } else if(!state.secondPick){
          state.secondPick = tile
          state.moves += 1
          if(state.firstPick.value === state.secondPick.value){
            state.firstPick.matched = true
            state.secondPick.matched = true
            state.matches += 1
            state.firstPick = null
            state.secondPick = null
          } else {
            state.locked = true
            setTimeout(() => {
              state.firstPick.revealed = false
              state.secondPick.revealed = false
              state.firstPick = null
              state.secondPick = null
              state.locked = false
              render()
            }, 700)
          }
        }
        render()
      }

      function renderRacerPanel(container){
        const state = gameState.spaceRacer
        const header = document.createElement('div'); header.className = 'game-info'
        header.innerHTML = `<div class="game-score-card"><strong>Space Racer</strong><span>${Math.floor(state.score)} pts</span><p>Tune the hyperdrive gauge and align energy pulses in a futuristic charge run.</p></div>`
        container.appendChild(header)

        const banner = document.createElement('div'); banner.className = 'game-banner'
        banner.style.backgroundImage = "url('https://images.unsplash.com/photo-1519125323398-675f0ddb6308?auto=format&fit=crop&w=900&q=80')"
        banner.innerHTML = `<h3>Energy alignment challenge</h3><p>Keep the ship centered in the glowing charge band to increase power and score.</p>`
        container.appendChild(banner)

        const board = document.createElement('div'); board.className='game-board'
        const canvas = document.createElement('canvas'); canvas.id='racer-canvas'; canvas.width = 760; canvas.height = 420
        board.appendChild(canvas)
        container.appendChild(board)

        const stats = document.createElement('div'); stats.className = 'game-score-card'
        stats.innerHTML = `<strong>Charge</strong><span>${Math.floor(state.charge)}%</span><p>Target zone is ${Math.round(state.targetSize*100)}% wide.</p>`
        container.appendChild(stats)

        const actions = document.createElement('div'); actions.className='game-actions'
        const leftBtn = document.createElement('button'); leftBtn.className='btn'; leftBtn.textContent='Shift Left'; leftBtn.addEventListener('click', () => moveRacer(-1))
        const rightBtn = document.createElement('button'); rightBtn.className='btn'; rightBtn.textContent='Shift Right'; rightBtn.addEventListener('click', () => moveRacer(1))
        const boostBtn = document.createElement('button'); boostBtn.className='btn'; boostBtn.textContent='Charge'; boostBtn.addEventListener('click', activateRacerBoost)
        const restartBtn = document.createElement('button'); restartBtn.className='btn'; restartBtn.textContent='Restart'; restartBtn.addEventListener('click', resetRacer)
        actions.append(leftBtn, rightBtn, boostBtn, restartBtn)
        container.appendChild(actions)

        const tips = document.createElement('div'); tips.className='game-tips'
        tips.innerHTML = '<p>Align with the glowing band before you charge. Good timing increases score and power.</p><p>Use Shift buttons to keep the ship inside the pulse zone.</p>'
        container.appendChild(tips)

        if(!racerAnimationId){
          state.lastTime = performance.now()
          document.addEventListener('keydown', handleRacerKeydown)
          racerAnimationId = requestAnimationFrame(racerLoop)
        }
      }

      function moveRacer(direction){
        const state = gameState.spaceRacer
        state.position = Math.max(0, Math.min(2, state.position + direction))
      }

      function activateRacerBoost(){
        const state = gameState.spaceRacer
        if(state.cooldown > 0) return
        state.cooldown = 1.6
        const alignment = Math.abs(state.position / 2 - state.targetPos)
        if(alignment < state.targetSize / 2){
          state.score += 18
          state.charge = Math.min(100, state.charge + 14)
        } else {
          state.score = Math.max(0, state.score - 10)
          state.charge = Math.max(0, state.charge - 12)
        }
        render()
      }

      function resetRacer(){
        gameState.spaceRacer = { position: 1, score: 0, charge: 72, targetPos: 0.5, targetSize: 0.24, lastTime: performance.now(), phase: 0, cooldown: 0 }
        if(racerAnimationId){ cancelAnimationFrame(racerAnimationId); racerAnimationId = null }
        document.removeEventListener('keydown', handleRacerKeydown)
        render()
      }

      function handleRacerKeydown(event){
        if(event.key === 'ArrowLeft' || event.key.toLowerCase() === 'a'){ moveRacer(-1) }
        if(event.key === 'ArrowRight' || event.key.toLowerCase() === 'd'){ moveRacer(1) }
        if(event.key.toLowerCase() === 's' || event.key === ' '){ activateRacerBoost() }
      }

      function racerLoop(timestamp){
        const state = gameState.spaceRacer
        const dt = (timestamp - state.lastTime) / 1000
        state.lastTime = timestamp
        state.phase += dt * 0.9
        state.targetPos = 0.16 + 0.68 * (0.5 + 0.5 * Math.sin(state.phase))
        state.charge = Math.max(0, state.charge - dt * 6)
        if(state.cooldown > 0){ state.cooldown = Math.max(0, state.cooldown - dt) }
        drawRacerScene()
        if(currentPage === 'games' && currentGame === 'space-racer'){
          racerAnimationId = requestAnimationFrame(racerLoop)
        } else {
          racerAnimationId = null
        }
      }

      function drawRacerScene(){
        const canvas = document.getElementById('racer-canvas')
        if(!canvas) return
        const ctx = canvas.getContext('2d')
        const width = canvas.width
        const height = canvas.height
        ctx.clearRect(0,0,width,height)
        const bg = ctx.createLinearGradient(0,0,width,height)
        bg.addColorStop(0,'#090d1d')
        bg.addColorStop(1,'#04060f')
        ctx.fillStyle = bg
        ctx.fillRect(0,0,width,height)

        const trackY = 96
        ctx.fillStyle = 'rgba(255,142,64,0.08)'
        ctx.fillRect(50, trackY, width - 100, 220)
        for(let i = 0; i < 3; i++){
          const x = 50 + i * (width - 100) / 3
          ctx.fillStyle = 'rgba(255,255,255,0.05)'
          ctx.fillRect(x + 6, trackY + 8, (width - 100) / 3 - 12, 204)
        }

        const state = gameState.spaceRacer
        const targetX = 50 + state.targetPos * (width - 100)
        const targetW = state.targetSize * (width - 100)
        const gradient = ctx.createLinearGradient(targetX - targetW, 0, targetX + targetW, 0)
        gradient.addColorStop(0,'rgba(33,255,205,0.08)')
        gradient.addColorStop(0.5,'rgba(33,255,205,0.24)')
        gradient.addColorStop(1,'rgba(33,255,205,0.08)')
        ctx.fillStyle = gradient
        ctx.fillRect(targetX - targetW / 2, trackY + 10, targetW, 200)

        const shipX = 50 + state.position * (width - 100) / 3 + (width - 100) / 6
        ctx.fillStyle = 'rgba(255,142,64,0.95)'
        ctx.beginPath()
        ctx.arc(shipX, trackY + 120, 28, 0, Math.PI * 2)
        ctx.fill()
        ctx.fillStyle = '#fff'
        ctx.beginPath()
        ctx.arc(shipX, trackY + 120, 12, 0, Math.PI * 2)
        ctx.fill()

        ctx.fillStyle = '#fff1dc'
        ctx.font = '700 22px Inter'
        ctx.fillText(`Score: ${Math.floor(state.score)}`, 28, 42)
        ctx.font = '600 16px Inter'
        ctx.fillStyle = '#f4c99a'
        ctx.fillText(`Charge: ${Math.floor(state.charge)}%`, 28, 70)
        ctx.fillText(`Next pulse zone`, 28, 98)

        const gaugeWidth = width - 120
        ctx.fillStyle = 'rgba(255,255,255,0.08)'
        ctx.fillRect(60, height - 60, gaugeWidth, 18)
        ctx.fillStyle = 'rgba(33,255,205,0.8)'
        ctx.fillRect(60, height - 60, (state.charge / 100) * gaugeWidth, 18)

        ctx.fillStyle = 'rgba(255,142,64,0.35)'
        ctx.fillRect(60, height - 96, (state.cooldown > 0 ? (state.cooldown / 1.6) : 0) * gaugeWidth, 12)
      }

      function handleObbyKeydown(event){
        if(event.key === 'ArrowLeft' || event.key.toLowerCase() === 'a'){ moveObby(-1) }
        if(event.key === 'ArrowRight' || event.key.toLowerCase() === 'd'){ moveObby(1) }
        if(event.key.toLowerCase() === 's' || event.key === ' '){ placeObbySegment() }
      }

      function placeObbySegment(){
        const state = gameState.obby
        if(state.cooldown > 0 || !state.alive) return
        const correct = state.position === state.pattern[state.goalIndex]
        state.path.push({ lane: state.position, correct })
        if(correct){
          state.score += 14
          state.goalIndex += 1
          if(state.goalIndex >= state.pattern.length){
            state.alive = false
          }
        } else {
          state.score = Math.max(0, state.score - 12)
          state.goalIndex = 0
          state.path = []
        }
        state.cooldown = 0.9
        render()
      }

      function moveObby(direction){
        const state = gameState.obby
        state.position = Math.max(0, Math.min(2, state.position + direction))
      }

      function resetObby(){
        gameState.obby = { position: 1, score: 0, alive: true, path: [], pattern: [], goalIndex: 0, lastTime: performance.now(), phase: 0, cooldown: 0 }
        if(obbyAnimationId){ cancelAnimationFrame(obbyAnimationId); obbyAnimationId=null }
        document.removeEventListener('keydown', handleObbyKeydown)
        render()
      }

      function obbyLoop(timestamp){
        const state = gameState.obby
        const dt = (timestamp - state.lastTime) / 1000
        state.lastTime = timestamp
        state.phase += dt * 1.1
        if(state.cooldown > 0){ state.cooldown = Math.max(0, state.cooldown - dt) }
        drawObby()
        if(currentPage === 'games' && currentGame === 'obby'){
          obbyAnimationId = requestAnimationFrame(obbyLoop)
        } else {
          obbyAnimationId = null
        }
      }

      function drawObby(){
        const canvas = document.getElementById('obby-canvas')
        if(!canvas) return
        const ctx = canvas.getContext('2d')
        const width = canvas.width
        const height = canvas.height
        ctx.clearRect(0,0,width,height)
        const bg = ctx.createLinearGradient(0,0,width,height)
        bg.addColorStop(0,'#10050f'); bg.addColorStop(1,'#040308')
        ctx.fillStyle = bg
        ctx.fillRect(0,0,width,height)

        const laneWidth = (width - 120) / 3
        for(let i=0;i<3;i++){
          const x = 60 + i * laneWidth
          ctx.fillStyle = i === gameState.obby.position ? 'rgba(255,142,64,0.18)' : 'rgba(255,142,64,0.08)'
          ctx.fillRect(x, 100, laneWidth - 14, 260)
          ctx.strokeStyle = 'rgba(255,142,64,0.20)'
          ctx.lineWidth = 2
          ctx.strokeRect(x, 100, laneWidth - 14, 260)
        }

        gameState.obby.pattern.forEach((lane, index) => {
          const iconX = 70 + lane * laneWidth + laneWidth / 2 - 12
          const iconY = 32
          ctx.fillStyle = index < gameState.obby.goalIndex ? 'rgba(33,255,205,0.95)' : 'rgba(255,142,64,0.55)'
          ctx.beginPath()
          ctx.arc(iconX, iconY, 12, 0, Math.PI * 2)
          ctx.fill()
          ctx.fillStyle = '#fff'
          ctx.font = '600 12px Inter'
          ctx.fillText(index + 1, iconX - 5, iconY + 5)
        })

        gameState.obby.path.forEach((segment, idx) => {
          const x = 60 + segment.lane * laneWidth
          const y = 130 + idx * 28
          ctx.fillStyle = segment.correct ? 'rgba(33,255,205,0.65)' : 'rgba(255,80,61,0.65)'
          ctx.fillRect(x + 8, y, laneWidth - 30, 20)
        })

        const selectedX = 60 + gameState.obby.position * laneWidth
        ctx.strokeStyle = 'rgba(255,255,255,0.85)'
        ctx.lineWidth = 3
        ctx.strokeRect(selectedX + 8, 340, laneWidth - 30, 40)

        ctx.fillStyle = '#fff1dc'
        ctx.font = '700 22px Inter'
        ctx.fillText(`Score: ${gameState.obby.score}`, 28, 48)
        ctx.font = '600 16px Inter'
        ctx.fillStyle = '#f4c99a'
        const statusLabel = gameState.obby.alive ? 'Building' : 'Completed'
        ctx.fillText(`Status: ${statusLabel}`, 28, 78)
        if(!gameState.obby.alive){
          ctx.fillStyle = 'rgba(0,0,0,0.65)'
          ctx.fillRect(140, 160, 480, 120)
          ctx.fillStyle = 'rgba(255,102,56,0.95)'
          ctx.font = '700 32px Inter'
          ctx.fillText('Path Complete', 220, 210)
          ctx.font = '500 18px Inter'
          ctx.fillStyle = '#fff1dc'
          ctx.fillText('Restart to generate a new neon route', 218, 245)
        }
      }

      // Debug view (optional)
      function renderDebug(){
        let dbg = document.querySelector('.stats-debug')
        if(!dbg){ dbg = document.createElement('div'); dbg.className='stats-debug'; document.body.appendChild(dbg) }
        dbg.innerHTML = '<strong>Stats (localStorage)</strong><br/>' + Object.keys(stats).map(k=>{
          const s = stats[k]; return `#${k}: ${s.watchTime || 0}s ${s.liked? '♥':' '}`
        }).join('<br/>')
      }

      // initial render
      render()

      // expose for console debugging
      window.__YUTOOB = { videos, stats, recommend }
    })()
    